#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int id;
        char first[51], last[51], email[101];
        if(scanf("%d %50s %50s %100s",&id,first,last,email)!=4) break;
        char *at=strchr(email,'@');
        if(at){
            const char *domain=at+1;
            if(strcmp(domain,"gmail.com")==0 || strcmp(domain,"yahoo.com")==0 || strcmp(domain,"hotmail.com")==0){
                printf("%d %s %s\n",id,first,last);
            }
        }
    }
    return 0;
}

