import sys
def main():
    data=sys.stdin.read().strip().splitlines()
    if not data:
        return
    T=int(data[0])
    out=[]
    for i in range(1,T+1):
        parts=data[i].split()
        if len(parts)<4:
            continue
        cid,first,last,email=parts[0],parts[1],parts[2],parts[3]
        at=email.find('@')
        if at!=-1:
            domain=email[at+1:]
            if domain in ("gmail.com","yahoo.com","hotmail.com"):
                out.append(f"{cid} {first} {last}")
    sys.stdout.write("\n".join(out))
if __name__=="__main__":
    main()

